**Program.cs**
```csharp
using OpenTelemetry.Metrics;
using OpenTelemetry.Resources;
using OpenTelemetry.Trace;

var builder = WebApplication.CreateBuilder(args);

var serviceName = "OrderApi";

builder.Services.AddOpenTelemetry()
    .ConfigureResource(r => r.AddService(serviceName))
    .WithTracing(tracing => tracing
        .AddAspNetCoreInstrumentation()
        .AddHttpClientInstrumentation()
        .AddSource(OrderService.ActivitySourceName)
        .AddOtlpExporter(opts =>
        {
            opts.Endpoint = new Uri("http://localhost:4317");
        }))
    .WithMetrics(metrics => metrics
        .AddAspNetCoreInstrumentation()
        .AddMeter(OrderService.MeterName)
        .AddOtlpExporter(opts =>
        {
            opts.Endpoint = new Uri("http://localhost:4317");
        }));

builder.Services.AddSingleton<OrderService>();
builder.Services.AddControllers();

var app = builder.Build();
app.MapControllers();
app.Run();
```

**OrderService.cs**
```csharp
using System.Diagnostics;
using System.Diagnostics.Metrics;

public class OrderService
{
    public const string ActivitySourceName = "OrderApi.OrderService";
    public const string MeterName = "OrderApi.OrderService";

    private static readonly ActivitySource _activitySource = new(ActivitySourceName);
    private static readonly Meter _meter = new(MeterName);
    private static readonly Counter<long> _ordersProcessed = _meter.CreateCounter<long>(
        "orders.processed",
        description: "Number of orders processed");

    public async Task<bool> ProcessOrder(Order order)
    {
        using var activity = _activitySource.StartActivity("OrderService.ProcessOrder");
        activity?.SetTag("order.id", order.Id);
        activity?.SetTag("order.total", order.Total);

        try
        {
            // Your processing logic here
            await Task.Delay(100); // simulate work

            _ordersProcessed.Add(1, new KeyValuePair<string, object?>("order.status", "success"));
            activity?.SetStatus(ActivityStatusCode.Ok);
            return true;
        }
        catch (Exception ex)
        {
            activity?.SetStatus(ActivityStatusCode.Error, ex.Message);
            activity?.RecordException(ex);
            _ordersProcessed.Add(1, new KeyValuePair<string, object?>("order.status", "error"));
            throw;
        }
    }
}

public record Order(string Id, decimal Total);
```

**Required packages** (add to `.csproj`):
```
OpenTelemetry.Extensions.Hosting
OpenTelemetry.Instrumentation.AspNetCore
OpenTelemetry.Instrumentation.Http
OpenTelemetry.Exporter.OpenTelemetryProtocol
```

Key points:
- `ActivitySource` is .NET's API for creating spans — registered via `AddSource()`
- `Meter`/`Counter` are registered via `AddMeter()`
- OTLP exporter sends to a collector at `localhost:4317` (gRPC); adjust as needed
- The custom span captures order metadata as tags and records exceptions automatically
